import React, { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { Box, Card, CardContent, Typography, CircularProgress } from "@mui/material";

function EmpDetails() {
  const { user_id } = useParams();
  const [workReports, setWorkReports] = useState([]);
  const [employeeName, setEmployeeName] = useState("");
  const [companies, setCompanies] = useState({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        // Fetch Work Reports
        const workResponse = await fetch(`http://localhost:5000/auth/${user_id}/work-reports`);
        const workData = await workResponse.json();
        setWorkReports(workData);

        // Fetch Employee Details
        const employeeResponse = await fetch("http://localhost:5000/auth");
        const employeeData = await employeeResponse.json();
        const employee = employeeData.find(emp => emp.id === parseInt(user_id));
        setEmployeeName(employee ? employee.name : "Unknown");

        // Fetch Company Details
        const companyResponse = await fetch("http://localhost:5000/companies");
        const companyData = await companyResponse.json();
        const companyMap = {};
        companyData.forEach(company => {
          companyMap[company.id] = company.company_name;
        });
        setCompanies(companyMap);

        setLoading(false);
      } catch (error) {
        console.error("Error fetching data:", error);
        setLoading(false);
      }
    };

    fetchData();
  }, [user_id]);

  return (
    <Box sx={{ padding: 3, maxWidth: 800, margin: "auto" }}>
      <Typography variant="h4" sx={{ textAlign: "center", marginBottom: 2 }}>
        Work Reports - {employeeName}
      </Typography>

      {loading ? (
        <Box sx={{ textAlign: "center", marginTop: 4 }}>
          <CircularProgress />
        </Box>
      ) : workReports.length > 0 ? (
        workReports.map((report) => (
          <Card key={report.id} sx={{ marginBottom: 2, padding: 2, boxShadow: 3 }}>
            <CardContent>
              <Typography variant="h6" sx={{ fontWeight: "bold" }}>
                {report.machine_name}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Date: {new Date(report.date).toLocaleDateString()}
              </Typography>
              <Typography variant="body2">
                <strong>Nature of Complaint:</strong> {report.nature_of_complaint}
              </Typography>
              <Typography variant="body2">
                <strong>Solution:</strong> {report.solution}
              </Typography>
              <Typography variant="body2">
                <strong>Time:</strong> {new Date(report.in_time).toLocaleTimeString()} - {new Date(report.out_time).toLocaleTimeString()}
              </Typography>
              <Typography variant="body2">
                <strong>Status:</strong> {report.status}
              </Typography>
              <Typography variant="body2">
                <strong>Assistant:</strong> {report.assistant_name}
              </Typography>
              <Typography variant="body2">
                <strong>Company:</strong> {companies[report.company_id] || "Unknown"}
              </Typography>
            </CardContent>
          </Card>
        ))
      ) : (
        <Typography sx={{ textAlign: "center", marginTop: 4 }}>No work reports found.</Typography>
      )}
    </Box>
  );
}

export default EmpDetails;
